bomData.valueScript:
// Type of the Bom-Element (will be checked in order output)
let elementType='Partgroup';

// ProductionSite Category (to split the orders for different production sites)
let elementCategory='';

// Id of the parent to create the hierarchy
let parentId=part.pa_PartgroupBomId;

// Id of this element to identify the childs of this element
let elementId=part.pa_BomId;

// Name of the PartGroup
let name='Partgroup Drawer'

this.bom_ElementId=elementId
this.bom_ElementType=elementType;
this.bom_ParentId=parentId;
this.bom_Length=part._width;
this.bom_Width=part._depth;
this.bom_Thk = part._thickness;
this.bom_Name=name;
this.bom_PartId=part._id;
this.bom_ElementCategory=elementCategory
